// Отвечаем на callback_query (убираем часики у кнопки) и сохраняем mode
const callbackData = $input.item.json.callbackData;
const userId = $input.item.json.userId;
const chatId = $input.item.json.chatId;

let mode = '';
let modeLabel = '';
let natalTarget = '';

if (callbackData === 'mode_horoscope') {
  mode = 'horoscope';
  modeLabel = 'гороскоп';
} else if (callbackData === 'mode_compatibility') {
  mode = 'compatibility';
  modeLabel = 'совместимость';
} else if (callbackData === 'mode_natal') {
  mode = 'natal';
  modeLabel = 'натальная карта';
} else if (callbackData === 'natal_self') {
  mode = 'natal_self';
  modeLabel = 'натальная карта (для себя)';
  natalTarget = 'self';
} else if (callbackData === 'natal_other') {
  mode = 'natal_other';
  modeLabel = 'натальная карта (другой)';
  natalTarget = 'other';
}

return [{
  json: {
    ...$input.item.json,
    mode,
    modeLabel,
    natalTarget
  }
}];

const output = $input.item.json.output || '';

// Попытаемся найти JSON в ответе
const jsonMatch = output.match(/\{[\s\S]*\"onboarding_complete\"[\s\S]*\}/);

if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.onboarding_complete === true) {
      const preferredTime = parsed.preferred_time || '09:00';
      return [{
        json: {
          is_onboarding_done: true,
          first_name: parsed.first_name || '',
          birth_date: parsed.birth_date || '',
          city: parsed.city || '',
          preferred_time: preferredTime,
          timezone: parsed.timezone || 'Europe/Moscow',
          message: `${parsed.first_name}, всё готово 🌟\n\nКаждый день в ${preferredTime} буду присылать тебе персональный прогноз. Можешь прямо сейчас написать, что тебя интересует — прогноз на сегодня, неделю или месяц 🔮`
        }
      }];
    }
  } catch (e) {
    // не JSON — продолжаем диалог
  }
}

return [{
  json: {
    is_onboarding_done: false,
    message: output
  }
}];

// Фильтруем пользователей, которым сейчас нужно отправить прогноз
const users = $input.all();
const nowUTC = new Date();

const usersToNotify = [];

for (const user of users) {
  const tz = user.json.timezone || 'Europe/Moscow';
  const preferredTime = user.json.preferred_time || '09:00';
  const lastSent = user.json.last_daily_sent || '';

  const userTimeStr = nowUTC.toLocaleTimeString('ru-RU', {
    timeZone: tz,
    hour: '2-digit',
    minute: '2-digit',
    hour12: false
  });

  const userDateStr = nowUTC.toLocaleDateString('ru-RU', {
    timeZone: tz,
    year: 'numeric',
    month: '2-digit',
    day: '2-digit'
  });

  const [curH, curM] = userTimeStr.split(':').map(Number);
  const [prefH, prefM] = preferredTime.split(':').map(Number);

  const curTotalMin = curH * 60 + curM;
  const prefTotalMin = prefH * 60 + prefM;
  const diffMinutes = Math.abs(curTotalMin - prefTotalMin);

  let alreadySentToday = false;
  if (lastSent) {
    const lastSentDate = new Date(lastSent).toLocaleDateString('ru-RU', {
      timeZone: tz,
      year: 'numeric',
      month: '2-digit',
      day: '2-digit'
    });
    alreadySentToday = lastSentDate === userDateStr;
  }

  if (diffMinutes <= 14 && !alreadySentToday) {
    usersToNotify.push({
      json: {
        telegram_id: user.json.telegram_id,
        first_name: user.json.first_name,
        last_name: user.json.last_name,
        birth_date: user.json.birth_date,
        city: user.json.city,
        timezone: tz,
        preferred_time: preferredTime,
        user_current_time: userTimeStr,
        user_current_date: userDateStr
      }
    });
  }
}

if (usersToNotify.length === 0) {
  return [];
}

return usersToNotify;

const output = $input.item.json.output || '';

if (output.includes('ДАННЫЕ_СОБРАНЫ')) {
  // Parse collected data
  const nameMatch = output.match(/имя:\s*(.+)/i);
  const dateMatch = output.match(/дата_рождения:\s*(.+)/i);
  const cityMatch = output.match(/город:\s*(.+)/i);

  const otherName = nameMatch ? nameMatch[1].trim() : '';
  const otherDate = dateMatch ? dateMatch[1].trim() : '';
  const otherCity = cityMatch ? cityMatch[1].trim() : '';

  return [{
    json: {
      ...$input.item.json,
      dataReady: true,
      otherName,
      otherDate,
      otherCity,
      messageToUser: null
    }
  }];
} else {
  // Still collecting — pass through agent's question to user
  return [{
    json: {
      ...$input.item.json,
      dataReady: false,
      messageToUser: output
    }
  }];
}

// Проверка подписки на канал MAX через пагинацию
const channelId = '-71330141790344';
const token = 'f9LHodD0cOKwdUROqAYYQEHJy9BDPFABPH9aym21zkZFQEOUn5FOixpjk9SjzMo3FMnF-Q52G86Jpz8M2x6r';
const userId = String($('Разбираем апдейт').item.json.userId);

let marker = null;
let isMember = false;
const maxPages = 50;

for (let page = 0; page < maxPages; page++) {
  let url = `https://platform-api.max.ru/chats/${channelId}/members`;
  if (marker) url += `?marker=${marker}`;

  const response = await fetch(url, {
    method: 'GET',
    headers: { 'Authorization': token }
  });

  const body = await response.json();
  const members = body.members || [];

  if (members.some(m => String(m.user_id) === userId)) {
    isMember = true;
    break;
  }

  if (!body.marker) break;
  marker = body.marker;
}

return [{ json: { is_member: isMember, checked_user_id: userId } }];

