// Если пользователь нажал "Я подписался", берём current_mode из Sheets
// Иначе используем mode из callback

const callbackData = $('Парсим callback').item.json.callbackData;
const parsedMode = $('Парсим callback').item.json.mode;
const sheetsData = $('Проверяем юзера (callback)').item.json;

let resolvedMode = parsedMode;

if (callbackData === 'check_subscription') {
  resolvedMode = sheetsData.current_mode || '';
}

return [{
  json: {
    ...$('Парсим callback').item.json,
    mode: resolvedMode,
    resolvedFromSheets: callbackData === 'check_subscription'
  }
}];

// Определяем тип входящего апдейта от Max Trigger
const update = $input.item.json;

const updateType = update.update_type || '';

const isCallback = updateType === 'message_callback';
const isMessage  = updateType === 'message_created';
const isBotStart = updateType === 'bot_started';

let chatId, userId, text, callbackData, username, firstName;

// Универсальный фолбек: всегда пытаемся достать chatId из message.recipient.chat_id
const fallbackChatId = update.message?.recipient?.chat_id || '';

if (isCallback) {
  // update.callback — объект callback
  const cb = update.callback;
  userId   = cb.user?.user_id || '';
  username = cb.user?.username || '';
  firstName = cb.user?.name || '';
  chatId   = cb.message?.recipient?.chat_id || fallbackChatId;
  callbackData = cb.payload || '';
  text = '';

} else if (isMessage) {
  // update.message — объект сообщения
  const msg = update.message;
  userId    = msg.sender?.user_id || '';
  username  = msg.sender?.username || '';
  firstName = msg.sender?.name || '';
  chatId    = msg.recipient?.chat_id || fallbackChatId;
  text      = msg.body?.text || '';
  callbackData = '';

} else if (isBotStart) {
  // update.user — пользователь, update.chat_id — чат
  userId    = update.user?.user_id || '';
  username  = update.user?.username || '';
  firstName = update.user?.name || '';
  chatId    = update.chat_id || fallbackChatId;
  text      = '';
  callbackData = '';

} else {
  // Неизвестный тип — пробуем фолбек
  chatId = fallbackChatId;
  userId = username = firstName = text = callbackData = '';
}

const isStart = text === '/start' || isBotStart;

return [{
  json: {
    chatId,
    userId,
    username,
    firstName,
    text,
    callbackData,
    isCallback,
    isMessage,
    isStart,
    updateType,
    isVoice: !!(update.message?.body?.attachments?.some(a => a.type === 'audio'))
  }
}];
